package com.example.webhookhandler;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.TextNode;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.client.HttpClientErrorException;
import org.springframework.web.client.HttpServerErrorException;
import org.springframework.web.client.ResourceAccessException;
import org.springframework.web.client.RestTemplate;

import java.net.MalformedURLException;
import java.net.URISyntaxException;
import java.net.URL;

@RestController
public class WebhookController {

    private final RestTemplate restTemplate;
    private final ObjectMapper objectMapper;

    public WebhookController(RestTemplate restTemplate, ObjectMapper objectMapper) {
        this.restTemplate = restTemplate;
        this.objectMapper = objectMapper;
    }

    @PostMapping("/webhook/process")
    public ResponseEntity<WebhookResponse> handleWebhook(@RequestBody WebhookRequest request) {
        String contentUrl = request.getContentUrl();
        if (contentUrl == null || contentUrl.trim().isEmpty()) {
            return new ResponseEntity<>(
                    new WebhookResponse(WebhookResponse.Status.FAILED, null, null, "Content URL cannot be empty."),
                    HttpStatus.BAD_REQUEST
            );
        }

        try {
            // Basic URL validation to catch malformed URLs early
            new URL(contentUrl).toURI();
        } catch (MalformedURLException | URISyntaxException e) {
            return new ResponseEntity<>(
                    new WebhookResponse(WebhookResponse.Status.FAILED, contentUrl, null, "Invalid content URL format: " + e.getMessage()),
                    HttpStatus.BAD_REQUEST
            );
        }

        try {
            // Fetch content from the provided URL
            ResponseEntity<String> externalResponse = restTemplate.getForEntity(contentUrl, String.class);
            String fetchedContentString = externalResponse.getBody();
            JsonNode fetchedContentJson = null;

            if (fetchedContentString != null && !fetchedContentString.isEmpty()) {
                try {
                    // Attempt to parse the fetched content as JSON
                    fetchedContentJson = objectMapper.readTree(fetchedContentString);
                } catch (Exception e) {
                    // If parsing as JSON fails, treat it as plain text
                    fetchedContentJson = new TextNode(fetchedContentString);
                }
            } else {
                 fetchedContentJson = new TextNode(""); // Empty content
            }

            // Return success response with fetched content
            return new ResponseEntity<>(
                    new WebhookResponse(WebhookResponse.Status.SUCCESS, contentUrl, fetchedContentJson, null),
                    HttpStatus.OK
            );

        } catch (HttpClientErrorException | HttpServerErrorException e) {
            // Handle HTTP client (4xx) and server (5xx) errors from the external URL
            String errorMessage = "Failed to fetch content from " + contentUrl + ": HTTP Status " + e.getStatusCode() + " - " + e.getStatusText();
            if (e.getResponseBodyAsString() != null && !e.getResponseBodyAsString().isEmpty()) {
                errorMessage += ". External response body: " + e.getResponseBodyAsString();
            }
            return new ResponseEntity<>(
                    new WebhookResponse(WebhookResponse.Status.FAILED, contentUrl, null, errorMessage),
                    e.getStatusCode() // Reflect the external service's error status code
            );
        } catch (ResourceAccessException e) {
            // Handle network-related errors (e.g., connection refused, timeout, unknown host)
            String errorMessage = "Network error while fetching content from " + contentUrl + ": " + e.getMessage();
            return new ResponseEntity<>(
                    new WebhookResponse(WebhookResponse.Status.FAILED, contentUrl, null, errorMessage),
                    HttpStatus.SERVICE_UNAVAILABLE
            );
        } catch (Exception e) {
            // Catch any other unexpected errors during the process
            String errorMessage = "An unexpected error occurred while processing content URL " + contentUrl + ": " + e.getMessage();
            return new ResponseEntity<>(
                    new WebhookResponse(WebhookResponse.Status.FAILED, contentUrl, null, errorMessage),
                    HttpStatus.INTERNAL_SERVER_ERROR
            );
        }
    }
}

